import { NextRequest, NextResponse } from 'next/server';
import { connectToDatabase } from '@/lib/mongodb';

export async function GET() {
  try {
    const { db } = await connectToDatabase();
    const payments = await db.collection('payments').find().toArray();
    return NextResponse.json(payments);
  } catch (error) {
    return NextResponse.json({ error: String(error) }, { status: 500 });
  }
}

export async function POST(req: NextRequest) {
  try {
    const data = await req.json();
    const { db } = await connectToDatabase();

    const existing = await db.collection('payments').findOne({ student_id: data.student_id });

    if (existing) {
      await db.collection('payments').updateOne(
        { _id: existing._id },
        { $set: { proof_file_path: data.proof_file_path, payment_status: 'pending', verified_at: null } }
      );
      const payment = await db.collection('payments').findOne({ _id: existing._id });
      return NextResponse.json(payment);
    }

    const last = await db.collection('payments').find().sort({ id: -1 }).limit(1).toArray();
    const lastNum = last.length > 0 ? parseInt(last[0].id.replace('p', ''), 10) : 0;
    const newId = 'p' + String(lastNum + 1).padStart(3, '0');

    const payment = { id: newId, ...data, payment_status: 'pending', verified_at: null };
    await db.collection('payments').insertOne(payment);
    return NextResponse.json(payment);
  } catch (error) {
    return NextResponse.json({ error: String(error) }, { status: 500 });
  }
}

export async function PUT(req: NextRequest) {
  try {
    const data = await req.json();
    const { db } = await connectToDatabase();
    const { id, ...updateData } = data;
    await db.collection('payments').updateOne({ id }, { $set: updateData });

    // Add audit log if payment verified
    if (updateData.payment_status === 'lunas' || updateData.payment_status === 'ditolak') {
      const payment = await db.collection('payments').findOne({ id });
      if (payment) {
        const student = await db.collection('students').findOne({ id: payment.student_id });
        const lastLog = await db.collection('auditLogs').find().sort({ id: -1 }).limit(1).toArray();
        const lastNum = lastLog.length > 0 ? parseInt(lastLog[0].id.replace('l', ''), 10) : 0;

        await db.collection('auditLogs').insertOne({
          id: 'l' + String(lastNum + 1).padStart(3, '0'),
          action: 'Pembayaran Diverifikasi',
          student: student?.name || '-',
          amount: 'Rp 250.000',
          date: new Date().toLocaleString('id-ID'),
          officer: data.officer || 'System',
        });
      }
    }

    return NextResponse.json({ success: true });
  } catch (error) {
    return NextResponse.json({ error: String(error) }, { status: 500 });
  }
}
